- Average texture refers to the mean value of hardness, chewiness, and crispiness; 
- The measurement_date refers to the date when the texture or taste measurement was taken; 
- Supplier details include name, contact person, email, phone number, and address; 
- Category information includes the category name and description for the product's category.

sql:
SELECT status, COUNT(*) AS number_of_products
FROM food_products
GROUP BY status;

SELECT COUNT(product_id) AS total_products
FROM food_products
WHERE category_id = (SELECT category_id FROM food_categories WHERE name = 'Bakery');

SELECT name, email, COUNT(*) AS number_of_tasters
FROM tasters
GROUP BY name, email;

SELECT COUNT(DISTINCT product_id) AS number_of_products
FROM defect_detection
WHERE defect_type = 'bruise';

SELECT COUNT(DISTINCT product_id) AS num_products_with_sweetness
FROM taste_measurements
WHERE sweetness > 3.0;
